import { useEffect, useState } from "react";
import "./styles/Books.css";

function HistoryByCategory() {
  const [grouped, setGrouped] = useState({});

  useEffect(() => {
    const history = JSON.parse(localStorage.getItem("borrowHistory")) || [];

    const groupedData = history.reduce((acc, book) => {
      if (!acc[book.category]) acc[book.category] = [];
      acc[book.category].push(book);
      return acc;
    }, {});

    setGrouped(groupedData);
  }, []);

  return (
    <div className="books-page">
      <h1 className="books-title">History by Category</h1>

      {Object.keys(grouped).length === 0 && (
        <p style={{ textAlign: "center" }}>No history yet</p>
      )}

      {Object.entries(grouped).map(([category, books]) => (
        <div key={category} style={{ marginBottom: "60px" }}>
          <h2 style={{ marginBottom: "20px", color: "#3b2416" }}>
            {category}
          </h2>

          <div className="books-grid">
            {books.map((book, i) => (
              <div key={i} className="book-card-vertical">
                <div className="book-image-box">
                  <img src={book.cover} alt={book.title} />
                </div>

                <h3 className="book-title">{book.title}</h3>
                <p className="book-author">{book.author}</p>
                <p style={{ fontSize: "12px", opacity: 0.7 }}>
                  Returned on {book.date}
                </p>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

export default HistoryByCategory;
